SELECT p.id, p.name, p.description, p.price, p.original_price, p.category_id, p.category_name, p.image, p.images, p.sales, p.status, p.is_hot, p.is_new, p.create_time, p.update_time, COALESCE(i.stock, 0) as stock FROM product p LEFT JOIN inventory i ON i.item_id = p.id AND i.type = 'product'
p.status = 1 AND COALESCE(i.stock, 0) > 0
AND (p.name LIKE CONCAT('%', #{keyword}, '%') OR p.description LIKE CONCAT('%', #{keyword}, '%'))
AND p.category_id IN ( SELECT id FROM product_category WHERE id = #{categoryId} OR parent_id = #{categoryId} )
AND p.is_hot = #{isHot}
AND p.is_new = #{isNew}
ORDER BY is_hot DESC, is_new DESC, sales DESC, p.id DESC LIMIT #{offset}, #{limit}

SELECT p.id, p.name, p.description, p.price, p.original_price, p.category_id, p.category_name, p.image, p.images, p.sales, p.status, p.is_hot, p.is_new, DATE_FORMAT(p.create_time, '%Y-%m-%d %H:%i:%s') as create_time, COALESCE(i.stock, 0) as stock FROM product p LEFT JOIN inventory i ON i.item_id = p.id AND i.type = 'product'
AND p.name LIKE CONCAT('%', #{keyword}, '%')
AND p.category_id = #{categoryId}
AND p.status = #{status}
ORDER BY p.id DESC LIMIT #{offset}, #{limit}

SELECT COUNT(*)
FROM product p


        AND p.name LIKE CONCAT('%', #{keyword}, '%')


        AND p.category_id = #{categoryId}


        AND p.status = #{status}

