name = #{name}, description = #{description}, price = #{price}, original_price = #{originalPrice}, category_id = #{categoryId}, category_name = #{categoryName}, image = #{image}, images = #{images}, status = #{status}, is_hot = #{isHot}, is_new = #{isNew},
